+  ctx.globalAlpha = 0.15;
+  ctx.fillStyle = color;
+  ctx.fillRect(pad, pad, size - pad * 2, size - pad * 2);
+  const tex = new THREE.CanvasTexture(c);
+  tex.needsUpdate = true;
