+    ($wasm:ident <=> $inner:path { $($variant:ident),+ $(,)? }) => {
+        impl From<$inner> for $wasm {
+            fn from(v: $inner) -> Self {
+                match v { $( <$inner>::$variant => $wasm::$variant, )+ }
+            }
+        }
+        impl From<$wasm> for $inner {
+            fn from(v: $wasm) -> Self {
+                match v { $( $wasm::$variant => <$inner>::$variant, )+ }
+            }
+        }
+    };
+}
