+    console.log(`  ✓ ${msg}`);
+  } else {
+    fail++;
+    console.error(`  ✗ ${msg}`);
+  }
+}
+
+function assertEqual(a, b, msg) {
+  assert(a === b, `${msg} (got ${a}, expected ${b})`);
+}
+
+// ---------- Load WASM ----------
