+console.log('\n--- Coherence Gate ---');
+const gate = new ThresholdGateWasm(config);
+const ctx = new GateContextWasm(
+  42, 1, 1000000n, 15n,
+  '00000000000000000000000000000000',
+  1.0, 0.1,
+  RegimeLabelWasm.Calm,
+  10,
